<?php
namespace Tests\Feature\Hr;
use App\Models\LegalEntity; use App\Models\User; use App\Modules\Hr\Advance\Actions\CreateAdvanceAction; use App\Modules\Hr\Advance\Actions\DecideAdvanceAction; use App\Modules\Hr\Advance\Actions\PayAdvanceAction; use App\Modules\Hr\Advance\Actions\RecordAdvanceRepaymentAction; use App\Modules\Hr\Advance\Enums\AdvanceStatus; use App\Modules\Hr\Advance\Enums\AdvanceTransactionType; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Personnel\Models\HrEmployee; use Illuminate\Support\Facades\DB; use Tests\TestCase;
class AdvanceWorkflowTest extends TestCase { use RefreshHrDatabase; private User $user; private HrEmployee $employee; protected function setUp():void{parent::setUp();(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$this->user=User::factory()->create(['role_id'=>$role]);$this->actingAs($this->user);$tenant=LegalEntity::create(['user_id'=>$this->user->id,'name'=>'Avans','tax_number'=>'4545454545','is_active'=>true]);app(TenantContext::class)->set($tenant);$this->employee=HrEmployee::withoutGlobalScope('tenant')->create(['legal_entity_id'=>$tenant->id,'user_id'=>$this->user->id,'employee_number'=>'ADV01','national_id_encrypted'=>'enc','national_id_hash'=>'adv-h','national_id_last_four'=>'0001','first_name'=>'Avans','last_name'=>'Test','status'=>'active']);}
public function test_advance_two_stage_payment_and_immutable_repayment_ledger():void{$a=app(CreateAdvanceAction::class)->execute($this->employee,['requested_amount'=>1000,'installment_count'=>2,'requested_payment_date'=>now()->addDay()->toDateString(),'reason'=>'Seyahat']);$this->assertSame(AdvanceStatus::PendingManager,$a->status);$a=app(DecideAdvanceAction::class)->approve($a);$this->assertSame(AdvanceStatus::PendingHr,$a->status);$a=app(DecideAdvanceAction::class)->approve($a);$payKey='bad0c7c7-761a-42d9-afd3-944e913f4150';$a=app(PayAdvanceAction::class)->execute($a,'BANK-1',$payKey);app(PayAdvanceAction::class)->execute($a,'BANK-1',$payKey);$this->assertSame(AdvanceStatus::Paid,$a->status);$this->assertDatabaseHas('hr_integration_outbox',['target'=>'finance','event_type'=>'advance_paid','source_id'=>$a->id]);$a=app(RecordAdvanceRepaymentAction::class)->execute($a,400,'BORDRO-1',AdvanceTransactionType::PayrollDeduction);$this->assertSame('600.00',$a->outstanding_amount);$this->assertDatabaseHas('hr_integration_outbox',['target'=>'payroll','event_type'=>'advance_payroll_deduction']);$repayKey='60629a08-9841-42cc-a827-5e24410231d8';$a=app(RecordAdvanceRepaymentAction::class)->execute($a,600,'BANK-2',AdvanceTransactionType::Repayment,$repayKey);app(RecordAdvanceRepaymentAction::class)->execute($a,600,'BANK-2',AdvanceTransactionType::Repayment,$repayKey);$this->assertSame(AdvanceStatus::Settled,$a->status);$this->assertCount(3,$a->transactions()->get());}
public function test_repayment_cannot_exceed_balance():void{$a=app(CreateAdvanceAction::class)->execute($this->employee,['requested_amount'=>100,'requested_payment_date'=>now()->toDateString(),'reason'=>'Test']);$a=app(DecideAdvanceAction::class)->approve($a);$a=app(DecideAdvanceAction::class)->approve($a);$a=app(PayAdvanceAction::class)->execute($a,'PAY');$this->expectException(\Symfony\Component\HttpKernel\Exception\HttpException::class);app(RecordAdvanceRepaymentAction::class)->execute($a,101,'OVER');}
public function test_source_key_is_idempotent():void{$key='a03b978b-ad16-4c34-9967-266bd948da40';$data=['requested_amount'=>250,'requested_payment_date'=>now()->toDateString(),'reason'=>'İhtiyaç'];$one=app(CreateAdvanceAction::class)->execute($this->employee,$data,$key);$two=app(CreateAdvanceAction::class)->execute($this->employee,$data,$key);$this->assertSame($one->id,$two->id);$this->assertDatabaseCount('hr_advances',1);} }
